// Filter patients whose follow-up is tomorrow, status is pending, and haven't been over-messaged
const items = $input.all();
const tz = $env.TIMEZONE || 'Asia/Kolkata';
const maxMessages = parseInt($env.MAX_MESSAGE_COUNT) || 5;
const minHours = parseInt($env.MIN_HOURS_BETWEEN_MESSAGES) || 23;

// Get tomorrow's date in local timezone (YYYY-MM-DD)
const now = new Date();
const tomorrow = new Date(now);
tomorrow.setDate(tomorrow.getDate() + 1);
const tomorrowStr = tomorrow.toLocaleDateString('en-CA', { timeZone: tz }); // en-CA = YYYY-MM-DD

const filtered = items.filter(item => {
  const p = item.json;

  // follow_up_date comes as a Date object or ISO string from Supabase
  const fuDate = p.follow_up_date ? new Date(p.follow_up_date).toLocaleDateString('en-CA', { timeZone: tz }) : null;
  if (!fuDate || fuDate !== tomorrowStr) return false;

  // Must be in pending state
  if (p.status && p.status !== 'pending') return false;

  // Must not exceed message limit
  const msgCount = parseInt(p.message_count) || 0;
  if (msgCount >= maxMessages) return false;

  // Must have a valid E.164 phone number
  if (!p.phone || !/^\+[1-9]\d{6,14}$/.test(p.phone)) return false;

  // Must not have been messaged within the last minHours hours
  if (p.last_message_sent) {
    const lastSent = new Date(p.last_message_sent);
    const hoursSince = (now - lastSent) / (1000 * 60 * 60);
    if (hoursSince < minHours) return false;
  }

  return true;
});

if (filtered.length === 0) {
  return [{ json: { _skip: true, reason: 'No patients to message today', tomorrowStr } }];
}

return filtered.map(item => ({
  json: {
    ...item.json,
    _workflow: 'workflow-1-followup-reminder',
    _message_type: 'follow_up_reminder',
    _to_phone: item.json.phone.replace(/^\+/, ''),
    _name: item.json.name || 'there',
    _doctor_name: item.json.doctor_name || $env.DEFAULT_DOCTOR_NAME || 'your doctor',
    _clinic_name: item.json.clinic_name || $env.DEFAULT_CLINIC_NAME || 'our clinic'
  }
}));
